import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { moviesAPI } from '../utils/api';
import '../styles/MovieCard.css';

const MovieCard = ({ movie, onDelete }) => {
  const navigate = useNavigate();
  const [showDeleteModal, setShowDeleteModal] = useState(false);
  const [showDetailsModal, setShowDetailsModal] = useState(false); // Состояние для модального окна деталей
  const [isDeleting, setIsDeleting] = useState(false);

  const handleDelete = async () => {
    setIsDeleting(true);
    try {
      await moviesAPI.delete(movie._id);
      onDelete(movie._id);
      setShowDeleteModal(false);
    } catch (error) {
      console.error('Error deleting movie:', error);
    } finally {
      setIsDeleting(false);
    }
  };

  const getStatusColor = (status) => {
    switch(status) {
      case 'watched': return 'status-watched';
      case 'watching': return 'status-watching';
      default: return 'status-plan';
    }
  };

  return (
    <>
      <div className="movie-card">
        <div className="movie-poster">
          {movie.posterUrl ? (
            <img src={movie.posterUrl} alt={movie.title} />
          ) : (
            <div className="no-poster">🎬</div>
          )}
        </div>
        <div className="movie-info-short">
          <h3 className="movie-title">{movie.title}</h3>
          <button 
            onClick={() => setShowDetailsModal(true)} 
            className="btn-details"
          >
            Подробнее
          </button>
        </div>
      </div>

      {/* Модальное окно с полной информацией о фильме */}
      {showDetailsModal && (
        <div className="details-modal-overlay" onClick={() => setShowDetailsModal(false)}>
          <div className="details-modal" onClick={e => e.stopPropagation()}>
            <button className="close-details-btn" onClick={() => setShowDetailsModal(false)}>
              &times;
            </button>
            <div className="details-content">
              <div className="details-poster">
                {movie.posterUrl ? (
                  <img src={movie.posterUrl} alt={movie.title} />
                ) : (
                  <div className="no-poster">🎬</div>
                )}
              </div>
              <div className="details-info">
                <h2>{movie.title}</h2>
                <p className="movie-director"><strong>Director:</strong> {movie.director || 'Unknown'}</p>
                <p className="movie-year"><strong>Year:</strong> {movie.year || 'N/A'}</p>
                <p className="movie-genre">{movie.genre}</p>
                <div className="movie-rating">
                  Rating: <span className="rating-value">{movie.rating}/10</span>
                </div>
                <div className={`movie-status ${getStatusColor(movie.status)}`}>
                  {movie.status}
                </div>
                {movie.review && (
                  <div className="movie-review-box">
                    <strong>Review:</strong>
                    <p>{movie.review}</p>
                  </div>
                )}
                
                <div className="movie-actions">
                  <button 
                    onClick={() => navigate(`/movies/edit/${movie._id}`)}
                    className="btn-edit"
                  >
                    Edit
                  </button>
                  <button 
                    onClick={() => {
                      setShowDetailsModal(false);
                      setShowDeleteModal(true);
                    }}
                    className="btn-delete"
                  >
                    Delete
                  </button>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Кастомное модальное окно для удаления */}
      {showDeleteModal && (
        <div className="delete-modal-overlay" onClick={() => setShowDeleteModal(false)}>
          <div className="delete-modal" onClick={e => e.stopPropagation()}>
            <h3>Delete Movie</h3>
            <p>Are you sure you want to delete <strong>"{movie.title}"</strong>? This action cannot be undone.</p>
            <div className="delete-modal-actions">
              <button 
                className="delete-modal-btn cancel"
                onClick={() => setShowDeleteModal(false)}
                disabled={isDeleting}
              >
                Cancel
              </button>
              <button 
                className="delete-modal-btn confirm"
                onClick={handleDelete}
                disabled={isDeleting}
              >
                {isDeleting ? 'Deleting...' : 'Delete'}
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  );
};

export default MovieCard;
